namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 2048;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    Ca6k04608CustomTilingData tiling;
    const gert::Shape *x_shape = context->GetInputShape(0);
    uint32_t totalElems = static_cast<uint32_t>(x_shape->GetOriginShape().GetShapeSize());
    uint32_t numChannels = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(1));
    uint32_t elemsPerChannel = totalElems / numChannels;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    float eps = attrs->GetAttrPointer<float>(0)[0];

    uint32_t maxTile = UB_BUDGET_BYTES / (2 * sizeof(float)); // in/out double buffer: 2 tiles
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;

    uint32_t tileLen = maxTile;
    if (elemsPerChannel < tileLen) {
        tileLen = AlignDown(elemsPerChannel, ALIGN_ELEMS);
        if (tileLen == 0) tileLen = elemsPerChannel;
    }

    uint32_t blockDim = numChannels; // one block per channel
    context->SetBlockDim(blockDim);

    tiling.set_totalElemsPerChannel(elemsPerChannel);
    tiling.set_tileLen(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_eps(eps);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

